INSERT INTO `expert_review` (`id`, `comment`, `created_at`, `critic_name`, `movie_title`, `rating`, `source`, `analysis_id`, `source_id`, `content_id`) VALUES
	(1, '너무나 잔혹한 대가를 치러야 하는 통쾌함', '2026-04-23 05:39:19.000000', '이유채', '범죄도시4', '5', 'Cine21', 1, NULL, 1),
	(2, '이전 세편을 뭉텅뭉텅 썰어냈군', '2026-04-23 05:39:19.000000', '박평식', '범죄도시4', '4', 'Cine21', 1, NULL, 1),
	(3, '안 봐도 본 것처럼', '2026-04-23 05:39:19.000000', '이용철', '범죄도시4', '4', 'Cine21', 1, NULL, 1),
	(4, '불한당들과 폭력의 명분을 공유하는 여전한 양지의 다크 나이트', '2026-04-23 05:39:19.000000', '유선아', '범죄도시4', '5', 'Cine21', 1, NULL, 1),
	(5, '자신의 주먹에 의문을 품다가, 다시 또 풀스윙', '2026-04-23 05:39:19.000000', '김철홍', '범죄도시4', '5', 'Cine21', 1, NULL, 1),
	(6, '톰 크루즈, “누가 슈퍼맨이라고?”', '2026-04-23 05:39:22.000000', '김혜리', '미션 임파서블: 폴 아웃', '8', 'Cine21', 1, NULL, 2),
	(7, '서스펜스, 액션, 감정선. 그 어느 것 하나 놓치지 않는다', '2026-04-23 05:39:22.000000', '장영엽', '미션 임파서블: 폴 아웃', '8', 'Cine21', 1, NULL, 2),
	(8, '대담하다, 동종업계 최상의 서비스', '2026-04-23 05:39:22.000000', '박평식', '미션 임파서블: 폴 아웃', '7', 'Cine21', 1, NULL, 2),
	(9, '그 누구도 아닌 톰 크루즈 자신이 부여하고 완수하는 미션', '2026-04-23 05:39:22.000000', '이화정', '미션 임파서블: 폴 아웃', '8', 'Cine21', 1, NULL, 2),
	(10, '연기도, 촬영도, 이야기도 모두 스턴트한다', '2026-04-23 05:39:22.000000', '허남웅', '미션 임파서블: 폴 아웃', '8', 'Cine21', 1, NULL, 2),
	(11, '뛰어난 시리즈란 이런 것이다', '2026-04-23 05:39:22.000000', '이용철', '미션 임파서블: 폴 아웃', '7', 'Cine21', 1, NULL, 2),
	(12, '여성 캐릭터가 자리를 찾은 시리즈의 일단락', '2026-04-23 05:39:22.000000', '송형국', '미션 임파서블: 폴 아웃', '6', 'Cine21', 1, NULL, 2),
	(13, '킬러의 귀환. 그러나 복수가 아닌 자유를 갈망하는', '2026-04-23 05:39:25.000000', '조현나', '존 윅 4', '8', 'Cine21', 1, NULL, 3),
	(14, '다정한 남편이자 듬직한 견주인 킬러 시리즈의 종합판이자 업그레이드판', '2026-04-23 05:39:25.000000', '이유채', '존 윅 4', '7', 'Cine21', 1, NULL, 3),
	(15, '초심을 지키며 성실히 진화한 프랜차이즈의 모범사례', '2026-04-23 05:39:25.000000', '김혜리', '존 윅 4', '8', 'Cine21', 1, NULL, 3),
	(16, '지치도록 혼을 빼는 퀵스텝 블루스', '2026-04-23 05:39:25.000000', '박평식', '존 윅 4', '6', 'Cine21', 1, NULL, 3),
	(17, '볼거리에서 사연으로 진화하는 액션에 경탄하다 존경하게 된다', '2026-04-23 05:39:25.000000', '허남웅', '존 윅 4', '8', 'Cine21', 1, NULL, 3),
	(18, '벚꽃이 휘날리면, 새벽 해가 뜨면, 누가 친구인지 알 것이다', '2026-04-23 05:39:25.000000', '이용철', '존 윅 4', '8', 'Cine21', 1, NULL, 3),
	(19, '시네마의 시대는 끝났어. 알아. 하지만 오늘은 아니야', '2026-04-23 05:39:28.000000', '송경원', '탑건: 매버릭', '8', 'Cine21', 1, NULL, 4),
	(20, '톰 크루즈, 할리우드 스타의 ‘탑건’', '2026-04-23 05:39:28.000000', '허남웅', '탑건: 매버릭', '8', 'Cine21', 1, NULL, 4),
	(21, '고전, 장르, 리얼 스턴트, 극장의 힘을 믿는 무비스타, 톰 크루즈!', '2026-04-23 05:39:28.000000', '임수연', '탑건: 매버릭', '9', 'Cine21', 1, NULL, 4),
	(22, '배우, 인물, 영화의 40년 숙성은 이런 것!', '2026-04-23 05:39:28.000000', '이용철', '탑건: 매버릭', '9', 'Cine21', 1, NULL, 4),
	(23, '‘탑건’의 시작부터 끝까지, 톰 크루즈 레전드', '2026-04-23 05:39:28.000000', '김수영', '탑건: 매버릭', '9', 'Cine21', 1, NULL, 4),
	(24, '상상을 ‘그리는’ 대신 그것을 ‘찍는’ 모습을 상상한다', '2026-04-23 05:39:32.000000', '송경원', '매드 맥스: 분노의 도로', '9', 'Cine21', 1, NULL, 5),
	(25, '아드레날린은 예상했지만, 오프로드로 뚫고 나가는 감격까지', '2026-04-23 05:39:32.000000', '김혜리', '매드 맥스: 분노의 도로', '9', 'Cine21', 1, NULL, 5),
	(26, '펄펄, 노장의 싯누런 광기', '2026-04-23 05:39:32.000000', '박평식', '매드 맥스: 분노의 도로', '7', 'Cine21', 1, NULL, 5),
	(27, '거장이 약 빨고 만든 황홀한 걸작. 보고도 믿기지 않는다', '2026-04-23 05:39:32.000000', '황진미', '매드 맥스: 분노의 도로', '9', 'Cine21', 1, NULL, 5),
